import json, pathlib

ENTITY_DIR = pathlib.Path("memory/entities")
ENTITY_DIR.mkdir(parents=True, exist_ok=True)

class EntityRegistry:
    def __init__(self, user_id: str) -> None:
        self.user_id = user_id
        self._store: dict[str, Entity] = {}
        self._alias_map: dict[str, str] = {}   # alias -> entity_id
        self._load()

    def _path(self) -> pathlib.Path:
        p = ENTITY_DIR / self.user_id
        p.mkdir(parents=True, exist_ok=True)
        return p / "registry.json"

    def _load(self) -> None:
        path = self._path()
        if not path.exists():
            return
        raw = json.loads(path.read_text())
        for item in raw.get("entities", []):
            e = Entity(**item)
            self._store[e.entity_id] = e
            for alias in e.aliases:
                self._alias_map[alias.lower()] = e.entity_id

    def save(self) -> None:
        import dataclasses
        data = {"entities": [dataclasses.asdict(e) for e in self._store.values()]}
        self._path().write_text(json.dumps(data, indent=2))

    def get(self, name: str) -> Entity | None:
        key = name.lower()
        entity_id = self._alias_map.get(key) or key
        return self._store.get(entity_id)

    def upsert(self, entity: Entity) -> None:
        existing = self._store.get(entity.entity_id)
        if existing:
            existing.attributes.update(entity.attributes)
            existing.mention_count += 1
            existing.last_updated = datetime.utcnow().isoformat()
            for alias in entity.aliases:
                if alias not in existing.aliases:
                    existing.aliases.append(alias)
                    self._alias_map[alias.lower()] = entity.entity_id
        else:
            entity.mention_count = 1
            self._store[entity.entity_id] = entity
            self._alias_map[entity.name.lower()] = entity.entity_id
            for alias in entity.aliases:
                self._alias_map[alias.lower()] = entity.entity_id
        self.save()

    def all_entities(self) -> list[Entity]:
        return sorted(self._store.values(), key=lambda e: e.mention_count, reverse=True)

    def to_prompt_block(self, max_entities: int = 10) -> str:
        entities = self.all_entities()[:max_entities]
        if not entities:
            return ""
        lines = ["[KNOWN ENTITIES]"]
        for e in entities:
            lines.append(f"  • {e.to_compact_string()}")
        return "\n".join(lines)

def merge_entities(
    registry: EntityRegistry,
    source_id: str,
    target_id: str,
) -> None:
    """
    Merge the source entity into the target.
    All source attributes and aliases are copied to the target;
    the source is then removed.
    """
    source = registry._store.get(source_id)
    target = registry._store.get(target_id)
    if not source or not target:
        return

    # Merge attributes (target wins on conflict)
    for k, v in source.attributes.items():
        if k not in target.attributes:
            target.attributes[k] = v

    # Merge aliases
    for alias in source.aliases + [source.name]:
        if alias not in target.aliases and alias.lower() != target.name.lower():
            target.aliases.append(alias)
        registry._alias_map[alias.lower()] = target.entity_id

    target.mention_count += source.mention_count

    # Remove source
    del registry._store[source_id]
    registry._alias_map.pop(source_id, None)
    registry.save()


def detect_potential_duplicates(registry: EntityRegistry) -> list[tuple[str, str]]:
    """
    Return pairs of entity IDs that might refer to the same entity.
    Uses simple name-prefix matching as a heuristic.
    """
    entities = registry.all_entities()
    pairs = []
    for i, a in enumerate(entities):
        for b in entities[i + 1:]:
            if a.entity_type != b.entity_type:
                continue
            # Same first word (e.g. "Alice" and "Alice Smith")
            if a.name.split()[0].lower() == b.name.split()[0].lower():
                pairs.append((a.entity_id, b.entity_id))
    return pairs
